  '33c17e17-2082-4a54-a750-6a8ba472004d',
  '00000000-0000-0000-0000-000000000001',
  $escape$gin Routing — Routes, Parameters, and Group Prefixes$escape$,
  $escape$gin's router is built on httprouter, giving you zero-allocation, radix-tree-based routing. Define routes directly on the engine: `r.GET("/users", handler)`, `r.POST("/users", handler)`. Route parameters use the `:param` syntax — `r.GET("/users/:id", handler)` — and are retrieved via `c.Param("id")`. Wildcard segments use `*param`, matching everything including slashes: `/files/*path`.

Grouping routes with `r.Group("/api/v1")` returns a `*RouterGroup`, letting you attach a shared prefix and middleware to related endpoints without repetition. Middleware applied to a group only runs for that group's routes — not the full engine. Nest groups further for versioned APIs: a `/api` group containing a `/v1` subgroup.

Use `r.Any()` to register all HTTP methods on one path, or `r.Handle(method, path, handlers)` for dynamic method strings. Named routes aren't supported natively — if you need reverse routing, manage path constants yourself.$escape$,
  $escape$r := gin.Default()

// Basic routes
r.GET("/ping", func(c *gin.Context) {
    c.JSON(200, gin.H{"message": "pong"})
})

// Route parameter
r.GET("/users/:id", func(c *gin.Context) {
    id := c.Param("id")
    c.JSON(200, gin.H{"user_id": id})
})

// Grouped routes with shared prefix and middleware
api := r.Group("/api/v1", AuthMiddleware())
{
    api.GET("/posts", listPosts)
    api.POST("/posts", createPost)
    api.DELETE("/posts/:id", deletePost)
}

r.Run(":8080")$escape$,
  $escape$go$escape$,
