INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f7b00f9c-c9e9-48a2-9473-18ac4c8a2f68',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Error Handling — Global Middleware for Consistent Error Responses$escape$,
  $escape$Gin doesn't have a built-in global error handler, but you can build one using a custom middleware that intercepts errors set via c.Error() and formats them uniformly before the response is written. Call c.Error(err) anywhere in your handler chain — Gin appends it to c.Errors — then a single middleware at the end of the chain reads c.Errors.Last() and writes a structured JSON response. This keeps error-shaping logic out of individual handlers entirely. Define a canonical error type that carries an HTTP status, machine-readable code, and human message. Your middleware maps that type via errors.As(); anything unrecognized falls back to 500. Register the middleware after your routes with router.Use() or inline it as the last handler in a group. Pair this with Gin's c.AbortWithError() when you need to short-circuit the chain — it sets the status and appends to c.Errors in one call, so the middleware still owns the response body. The result: every error surface in your API returns the same JSON shape without duplicating response logic.$escape$,
  $escape$type AppError struct {
	Status  int    `json:"-"`
	Code    string `json:"code"`
	Message string `json:"message"`
}
func (e *AppError) Error() string { return e.Message }

func ErrorHandler() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Next()
		if len(c.Errors) == 0 {
			return
		}
		var appErr *AppError
		if errors.As(c.Errors.Last().Err, &appErr) {
			c.JSON(appErr.Status, appErr)
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"code": "INTERNAL", "message": "unexpected error"})
		}
	}
}$escape$,
  $escape$go$escape$,
