INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1fc13e25-a93d-42a1-b958-3fa70a6479fb',
  '00000000-0000-0000-0000-000000000001',
  $escape$gin Security Essentials — CORS, Rate Limiting, and Headers in One Setup$escape$,
  $escape$gin ships with no security defaults — you own the hardening. Start with `cors` via `github.com/gin-contrib/cors`: use `cors.New(cors.Config{AllowOrigins: []string{"https://yourdomain.com"}, AllowMethods: []string{"GET", "POST"}, AllowHeaders: []string{"Authorization", "Content-Type"}})` — never `cors.Default()` in production, which wildcards origins. Rate limiting belongs on the router group level using `github.com/ulule/limiter/v3` with its gin middleware; attach it before auth so unauthenticated flood is dropped early. Security headers aren't built-in — add them via a custom middleware that sets `X-Content-Type-Options`, `X-Frame-Options`, `Content-Security-Policy`, and `Strict-Transport-Security` on every response. For injection prevention, never interpolate route params directly into SQL — always bind to structs with `ShouldBindJSON` and validate with `go-playground/validator` tags like `binding:"required,alphanum"`. gin's `gin.SetMode(gin.ReleaseMode)` also disables debug stack traces in responses, a common info-leak vector.$escape$,
  $escape$package main

import (
	"github.com/gin-contrib/cors"
	"github.com/gin-gonic/gin"
)

func SecurityHeaders() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Header("X-Content-Type-Options", "nosniff")
		c.Header("X-Frame-Options", "DENY")
		c.Header("Strict-Transport-Security", "max-age=63072000; includeSubDomains")
		c.Header("Content-Security-Policy", "default-src 'self'")
		c.Next()
	}
}

func main() {
	gin.SetMode(gin.ReleaseMode)
	r := gin.New()
	r.Use(gin.Recovery())
	r.Use(SecurityHeaders())
	r.Use(cors.New(cors.Config{
		AllowOrigins: []string{"https://yourdomain.com"},
		AllowMethods: []string{"GET", "POST", "PUT", "DELETE"},
		AllowHeaders: []string{"Authorization", "Content-Type"},
	}))
	r.Run(":8080")
}$escape$,
