INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd8458c03-91bb-4231-aa2c-a26bff68953d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Performance — Connection Pooling, Async Handlers, and gzip Compression$escape$,
  $escape$Gin doesn't manage a database connection pool itself — that's your `*sql.DB` or GORM's underlying driver. Set `SetMaxOpenConns`, `SetMaxIdleConns`, and `SetConnMaxLifetime` once at startup and share the instance across handlers via `gin.Context` or dependency injection. Never open a new connection per request.

For async work inside a handler, copy the context with `c.Copy()` before spawning a goroutine. Accessing the original `*gin.Context` after the handler returns causes a data race since Gin recycles it into its sync.Pool.

Response compression is handled by `github.com/gin-contrib/gzip`. Wrap your router group with `gzip.Gzip(gzip.DefaultCompression)` — this transparently compresses responses when the client sends `Accept-Encoding: gzip`. Avoid wrapping health-check or metrics routes; compression overhead outweighs benefit on tiny payloads. Combine with `c.Header("Cache-Control", "public, max-age=3600")` on static API responses to cut repeat bandwidth. Together these three levers — pool tuning, safe goroutine dispatch, and selective compression — cover the most common Gin performance gaps in production.$escape$,
  $escape$package main

import (
	"database/sql"
	"net/http"
	"time"

	"github.com/gin-contrib/gzip"
	"github.com/gin-gonic/gin"
)

func main() {
	db, _ := sql.Open("postgres", dsn)
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(10)
	db.SetConnMaxLifetime(5 * time.Minute)

	r := gin.New()
	r.Use(gzip.Gzip(gzip.DefaultCompression))

	r.GET("/articles", func(c *gin.Context) {
		cCopy := c.Copy()
		go func() {
			// safe: uses copied context, original may be recycled
			_ = logAsync(cCopy, db)
		}()
		c.JSON(http.StatusOK, gin.H{"ok": true})
	})

	r.Run(":8080")
}$escape$,
  $escape$go$escape$,
