INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7d5d02fc-ed39-4ed8-80d8-c32ec29d5f5d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Configuration — Env Vars, Structs, and Secrets Done Right$escape$,
  $escape$Gin reads `GIN_MODE` natively — set it to `release` in production to silence debug logs and disable the colorized logger. Beyond that, Gin has no built-in config system, so pair it with `github.com/spf13/viper` or a plain struct loaded from env vars.

The idiomatic pattern is a typed `Config` struct populated via `os.Getenv` or `envconfig`, then injected into your router setup — never accessed globally mid-handler. Store secrets (DB passwords, API keys) in environment variables only; never in config files committed to source control. Use `.env` files locally with `godotenv.Load()` called before `viper.AutomaticEnv()`, so environment always wins over file values.

For `gin.Engine` itself, set `router.TrustedProxies` explicitly — leaving it as the default `["0.0.0.0/0"]` in production is a security hole. Combine config loading with `gin.SetMode` early in `main()`, before any middleware or route registration, so debug-only middleware like `gin.Logger()` can be conditionally attached based on the loaded config.$escape$,
  $escape$package main

import (
	"os"
	"github.com/gin-gonic/gin"
	"github.com/joho/godotenv"
)

type Config struct {
	Port      string
	DBDSN     string
	JWTSecret string
}

func loadConfig() Config {
	_ = godotenv.Load() // no-op if .env absent
	return Config{
		Port:      getEnv("PORT", "8080"),
		DBDSN:     os.Getenv("DATABASE_URL"),
		JWTSecret: os.Getenv("JWT_SECRET"),
	}
}

func getEnv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

func main() {
	cfg := loadConfig()
	gin.SetMode(os.Getenv("GIN_MODE")) // "release" in prod

	r := gin.New()
	_ = r.SetTrustedProxies([]string{"10.0.0.0/8"})

	if gin.Mode() != gin.ReleaseMode {
		r.Use(gin.Logger())
	}

	r.Run(":" + cfg.Port)
}$escape$,
